#include <stdio.h>
#include <openssl/bn.h>

void print_bn(const char *msg, const BIGNUM *a) {
    char *number_str = BN_bn2hex(a);
    printf("%s %s\n", msg, number_str);
    OPENSSL_free(number_str);
}

int main() {
    BN_CTX *ctx = BN_CTX_new();
    BIGNUM *n = BN_new();
    BIGNUM *e = BN_new();
    BIGNUM *s = BN_new();
    BIGNUM *decoded = BN_new();

    /*
     * This task shows the core RSA step in manual certificate verification:
     * decoded = signature^e mod n
     * Replace n/e/signature with values extracted from your own c1.pem and c0.pem.
     */
    BN_hex2bn(&n, "");
    BN_dec2bn(&e, "65537");
    BN_hex2bn(&s, "");

    BN_mod_exp(decoded, s, e, n, ctx);

    print_bn("Decoded signature block =", decoded);
    printf("Check PKCS#1 padding and SHA-256 digest manually against c0_body.bin hash.\n");

    BN_free(n);
    BN_free(e);
    BN_free(s);
    BN_free(decoded);
    BN_CTX_free(ctx);

    return 0;
}
